mapper.select:
select *
from shopping_cart
where user_id = #{userId}
  and dish_id = #{dishId}
  and (
    (#{dishFlavor} is null and dish_flavor is null)
    or dish_flavor = #{dishFlavor}
  )
limit 1

mapper.update:
update shopping_cart
set number = #{number}
where id = #{id}

